B.Zh=new A.ca("\u062f\u064a\u0631 \u0633\u064a\u062f\u0629 \u0635\u064a\u062f\u0646\u0627\u064a\u0627","Our Lady of Saidnaya Monastery",null,B.ds,u.u,"A Greek Orthodox monastery located in Saidnaya north of Damascus, dating to the 6th century. Thousands of Christians and Muslims pilgrimage here annually.",B.a9n,33.6996,36.375,"8:00 \u0635\u0628\u0627\u062d\u0627\u064b - 6:00 \u0645\u0633\u0627\u0621\u064b",null,!1)
