B.Zi=new A.ca("\u0645\u062f\u064a\u0646\u0629 \u062d\u0644\u0628 \u0627\u0644\u0642\u062f\u064a\u0645\u0629","Ancient City of Aleppo","Ancient City of Aleppo",B.bj,"\u062a\u0642\u0639 \u062d\u0644\u0628 \u0639\u0644\u0649 \u0645\u0641\u062a\u0631\u0642 \u0637\u0631\u0642 \u062a\u062c\u0627\u0631\u064a\u0629 \u0645\u0646\u0630 \u0627\u0644\u0623\u0644\u0641\u064a\u0629 \u0627\u0644\u062b\u0627\u0646\u064a\u0629 \u0642\u0628\u0644 \u0627\u0644\u0645\u064a\u0644\u0627\u062f. \u062a\u062a\u0645\u064a\u0632 \u0628\u0642\u0644\u0639\u062a\u0647\u0627 \u0627\u0644\u0634\u0647\u064a\u0631\u0629 \u0648\u0623\u0633\u0648\u0627\u0642\u0647\u0627 \u0627\u0644\u0645\u0633\u0642\u0648\u0641\u0629 \u0648\u0645\u062f\u0627\u0631\u0633\u0647\u0627 \u0648\u0642\u0635\u0648\u0631\u0647\u0627 \u0648\u0643\u0646\u0627\u0626\u0633\u0647\u0627 \u0648\u0645\u0633\u0627\u062c\u062f\u0647\u0627 \u0627\u0644\u062a\u064a \u062a\u0639\u0648\u062f \u0644\u0644\u062d\u0636\u0627\u0631\u0627\u062a \u0627\u0644\u0625\u0633\u0644\u0627\u0645\u064a\u0629 \u0648\u0627\u0644\u0628\u064a\u0632\u0646\u0637\u064a\u0629.","Located at the crossroads of several trade routes, Aleppo has been inhabited since the 2nd millennium BC. It is known for its citadel, covered souks, madrasas, and mosques.",B.a80,36.1992,37.1625,"\u0645\u0641\u062a\u0648\u062d \u0639\u0644\u0649 \u0645\u062f\u0627\u0631 \u0627\u0644\u0633\u0627\u0639\u0629",null,!0)
B.a55=s(["https://upload.wikimedia.org/wikipedia/commons/thumb/4/4e/Qatna.jpg/800px-Qatna.jpg"],t.s)
B.Zj=new A.ca("\u0642\u0637\u0646\u0627 - \u0627\u0644\u0645\u0634\u0631\u0641\u0629","Qatna (Tell Mishrifeh)",null,B.bj,"\u0645\u062f\u064a\u0646\u0629 \u0623\u062b\u0631\u064a\u0629 \u0645\u0646 \u0627\u0644\u0639\u0635\u0631 \u0627\u0644\u0628\u0631\u0648\u0646\u0632\u064a (2000-1200 \u0642.\u0645)\u060c \u062a\u0642\u0639 \u0639\u0644\u0649 \u0628\u0639\u062f 18 \u0643\u0645 \u0634\u0645\u0627\u0644 \u0634\u0631\u0642 \u062d\u0645\u0635. \u0643\u0627\u0646\u062a \u0645\u0645\u0644\u0643\u0629 \u0642\u0648\u064a\u0629 \u0646\u0627\u0641\u0633\u062a \u0645\u0627\u0631\u064a \u0648\u0625\u064a\u0628\u0644\u0627. \u0627\u0643\u062a\u0634\u0641 \u0641\u064a\u0647\u0627 \u0627\u0644\u0642\u0635\u0631 \u0627\u0644\u0645\u0644\u0643\u064a \u0648\u0627\u0644\u0645\u0642\u0628\u0631\u0629 \u0627\u0644\u0645\u0644\u0643\u064a\u0629 \u0627\u0644\u062a\u064a \u062a\u0636\u0645 \u0645\u0626\u0627\u062a \u0627\u0644\u0642\u0637\u0639 \u0627\u0644\u0623\u062b\u0631\u064a\u0629.","Bronze Age city (2000-1200 BC) located 18 km northeast of Homs. A powerful kingdom that rivaled Mari and Ebla. The royal palace and royal tomb containing hundreds of artifacts were discovered here.",B.a55,34.835,36.866,"8:00 \u0635\u0628\u0627\u062d\u0627\u064b - 3:00 \u0645\u0633\u0627\u0621\u064b",null,!1)
B.FB=s(["https://images.unsplash.com/photo-1582555172866-f73bb12defab?w=800"],t.s)
B.Zk=new A.ca("\u0645\u0645\u0644\u0643\u0629 \u0645\u0627\u0631\u064a \u0627\u0644\u0623\u062b\u0631\u064a\u0629","Royal Palace of Mari","Mari Archaeological Site",B.bj,"\u0639\u0627\u0635\u0645\u0629 \u0645\u0645\u0644\u0643\u0629 \u0642\u062f\u064a\u0645\u0629 \u0639\u0644\u0649 \u0627\u0644\u0641\u0631\u0627\u062a \u062a\u0639\u0648\u062f \u0644\u0644\u0623\u0644\u0641 \u0627\u0644\u062b\u0627\u0644\u062b \u0642\u0628\u0644 \u0627\u0644\u0645\u064a\u0644\u0627\u062f. \u0627\u0643\u062a\u0634\u0641 \u0641\u064a\u0647\u0627 \u0627\u0644\u0642\u0635\u0631 \u0627\u0644\u0645\u0644\u0643\u064a \u0627\u0644\u0630\u064a \u064a\u0636\u0645 300 \u063a\u0631\u0641\u0629 \u0648\u0623\u0631\u0634\u064a\u0641\u0627\u064b \u0636\u062e\u0645\u0627\u064b \u0645\u0646 \u0627\u0644\u0623\u0644\u0648\u0627\u062d \u0627\u0644\u0645\u0633\u0645\u0627\u0631\u064a\u0629. \u0645\u0646 \u0623\u0647\u0645 \u0645\u0645\u0627\u0644\u0643 \u0645\u0627 \u0628\u064a\u0646 \u0627\u0644\u0646\u0647\u0631\u064a\u0646 \u0627\u0644\u0642\u062f\u064a\u0645\u0629.","Capital of an ancient kingdom on the Euphrates dating to the 3rd millennium BC. The royal palace with 300 rooms and a vast archive of cuneiform tablets was discovered here.",B.FB,34.5514,40.8885,null,null,!0)
B.a8X=s(["https://upload.wikimedia.org/wikipedia/commons/thumb/7/7f/Ebla.jpg/800px-Ebla.jpg"],t.s)
B.Zl=new A.ca("\u0625\u064a\u0628\u0644\u0627 - \u062a\u0644 \u0645\u0631\u062f\u064a\u062e","Ebla (Tell Mardikh)","Ebla Archaeological Site",B.bj,"\u0645\u062f\u064a\u0646\u0629 \u0623\u062b\u0631\u064a\u0629 \u0647\u0627\u0645\u0629 \u0645\u0646 \u0627\u0644\u0639\u0635\u0631 \u0627\u0644\u0628\u0631\u0648\u0646\u0632\u064a (2400 \u0642.\u0645)\u060c \u062a\u0642\u0639 \u0639\u0644\u0649 \u0628\u0639\u062f 55 \u0643\u0645 \u062c\u0646\u0648\u0628 \u063a\u0631\u0628 \u062d\u0644\u0628. \u0627\u0643\u062a\u0634\u0641 \u0641\u064a\u0647\u0627 \u0623\u0631\u0634\u064a\u0641 \u0645\u0644\u0643\u064a \u064a\u0636\u0645 \u0623\u0643\u062b\u0631 \u0645\u0646 5000 \u0631\u0642\u064a\u0645 \u0637\u064a\u0646\u064a \u0645\u0633\u0645\u0627\u0631\u064a \u064a\u0648\u062b\u0642 \u0627\u0644\u062d\u064a\u0627\u0629 \u0627\u0644\u0633\u064a\u0627\u0633\u064a\u0629 \u0648\u0627\u0644\u0627\u0642\u062a\u0635\u0627\u062f\u064a\u0629 \u0641\u064a \u0627\u0644\u0623\u0644\u0641 \u0627\u0644\u062b\u0627\u0644\u062b \u0642\u0628\u0644 \u0627\u0644\u0645\u064a\u0644\u0627\u062f.","Major Bronze Age city (2400 BC) located 55 km southwest of Aleppo. A royal archive of over 5,000 cuneiform tablets documenting political and economic life in the 3rd millennium BC was discovered here.",B.a8X,35.798,36.798,"8:00 \u0635\u0628\u0627\u062d\u0627\u064b - 4:00 \u0645\u0633\u0627\u0621\u064b",null,!1)
