B.ZG=new A.ca("\u0645\u062a\u062d\u0641 \u062f\u064a\u0631 \u0627\u0644\u0632\u0648\u0631","Deir ez-Zor Museum",null,B.e0,"\u0645\u062a\u062d\u0641 \u0645\u062e\u0635\u0635 \u0644\u0622\u062b\u0627\u0631 \u0634\u0645\u0627\u0644 \u0634\u0631\u0642 \u0633\u0648\u0631\u064a\u0627 (\u0627\u0644\u062c\u0632\u064a\u0631\u0629). \u064a\u0636\u0645 \u0645\u0643\u062a\u0634\u0641\u0627\u062a \u0645\u0646 \u0645\u0648\u0627\u0642\u0639 \u062a\u0644 \u0628\u064a\u062f\u0631 \u0648\u062a\u0644 \u0628\u0631\u0627\u0643 \u0648\u062a\u0644 \u0644\u064a\u0644\u0627\u0646. \u064a\u062d\u062a\u0648\u064a \u0639\u0644\u0649 \u0645\u062c\u0645\u0648\u0639\u0629 \u0647\u0627\u0645\u0629 \u0645\u0646 \u0627\u0644\u0623\u0644\u0648\u0627\u062d \u0627\u0644\u0645\u0633\u0645\u0627\u0631\u064a\u0629 \u0648\u0627\u0644\u0627\u062e\u062a\u0627\u0645 \u0627\u0644\u0623\u0633\u0637\u0648\u0627\u0646\u064a\u0629.","Museum dedicated to the archaeology of northeastern Syria (Jezirah). Features finds from Tell Beydar, Tell Brak, and Tell Leilan. Contains an important collection of cuneiform tablets and cylinder seals.",B.a4m,35.333,40.133,"9:00 \u0635\u0628\u0627\u062d\u0627\u064b - 3:00 \u0645\u0633\u0627\u0621\u0627\u064b","100 \u0644.\u0633",!1)
