B.ZH=new A.ca("\u0633\u0648\u0642 \u0627\u0644\u062d\u0645\u064a\u062f\u064a\u0629","Al-Hamidiyah Souq",null,B.jo,"\u0623\u0643\u0628\u0631 \u0633\u0648\u0642 \u0645\u0633\u0642\u0648\u0641 \u0641\u064a \u0633\u0648\u0631\u064a\u0627\u060c \u0628\u0646\u064a \u0641\u064a \u0627\u0644\u0639\u0647\u062f \u0627\u0644\u0639\u062b\u0645\u0627\u0646\u064a \u0639\u0627\u0645 1780. \u064a\u0645\u062a\u062f \u0644\u0645\u0633\u0627\u0641\u0629 422 \u0645\u062a\u0631\u0627\u064b \u0628\u0639\u0631\u0636 15 \u0645\u062a\u0631\u0627\u064b \u0641\u064a \u0642\u0644\u0628 \u0645\u062f\u064a\u0646\u0629 \u062f\u0645\u0634\u0642 \u0627\u0644\u0642\u062f\u064a\u0645\u0629. \u064a\u062a\u0645\u064a\u0632 \u0628\u0633\u0642\u0641\u0647 \u0627\u0644\u062d\u062f\u064a\u062f\u064a \u0627\u0644\u0645\u0644\u064a\u0621 \u0628\u062b\u0642\u0648\u0628 \u0627\u0644\u0631\u0635\u0627\u0635 \u0645\u0646 \u0627\u0644\u062d\u0642\u0628\u0629 \u0627\u0644\u0639\u062b\u0645\u0627\u0646\u064a\u0629.","The largest covered souq in Syria, built during the Ottoman era in 1780. It stretches 422 metres long and 15 metres wide in the heart of old Damascus.",B.a9g,33.5108,36.3008,"9:00 \u0635\u0628\u0627\u062d\u0627\u064b - 8:00 \u0645\u0633\u0627\u0621\u064b",null,!1)
