B.ZM=new A.ca("\u062f\u0648\u0631\u0627 \u0623\u0648\u0631\u0648\u0628\u0648\u0633","Dura-Europos",null,B.bj,'\u0645\u062f\u064a\u0646\u0629 \u0647\u064a\u0644\u064a\u0646\u0633\u062a\u064a\u0629 \u0639\u0644\u0649 \u0646\u0647\u0631 \u0627\u0644\u0641\u0631\u0627\u062a (303 \u0642.\u0645 - 256 \u0645)\u060c \u062a\u0642\u0639 \u0642\u0631\u0628 \u0628\u0644\u062f\u0629 \u0627\u0644\u0635\u0627\u0644\u062d\u064a\u0629. \u062a\u0636\u0645 \u0623\u0642\u062f\u0645 \u0643\u0646\u064a\u0633\u0629 \u0645\u0646\u0632\u0644\u064a\u0629 \u0645\u0639\u0631\u0648\u0641\u0629 \u0641\u064a \u0627\u0644\u0639\u0627\u0644\u0645 (240 \u0645) \u0648\u0623\u0642\u062f\u0645 \u0643\u0646\u064a\u0633 \u064a\u0647\u0648\u062f\u064a \u0645\u0632\u064a\u0646 \u0628\u0644\u0648\u062d\u0627\u062a \u062c\u062f\u0627\u0631\u064a\u0629. \u062a\u0639\u0631\u0641 \u0628\u0627\u0633\u0645 "\u0628\u0648\u0645\u0628\u064a \u0627\u0644\u0635\u062d\u0631\u0627\u0621".','Hellenistic city on the Euphrates (303 BC - 256 AD) near the village of Salhiyah. Contains the oldest known house church in the world (240 AD) and the oldest decorated synagogue with wall paintings. Known as "Pompeii of the Desert".',B.a3l,34.747,40.73,"8:00 \u0635\u0628\u0627\u062d\u0627\u064b - 3:00 \u0645\u0633\u0627\u0621\u064b",null,!1)
B.ZN=new A.ca("\u0643\u0646\u064a\u0633\u0629 \u0645\u0627\u0631 \u0633\u0645\u0639\u0627\u0646 \u0627\u0644\u0639\u0645\u0648\u062f\u064a","Church of Saint Simeon Stylites","Ancient Villages of Northern Syria",B.bj,"\u0645\u0646 \u0623\u0642\u062f\u0645 \u0627\u0644\u0643\u0646\u0627\u0626\u0633 \u0627\u0644\u0628\u064a\u0632\u0646\u0637\u064a\u0629 \u0627\u0644\u0628\u0627\u0642\u064a\u0629\u060c \u0628\u0646\u064a\u062a \u0641\u064a \u0627\u0644\u0642\u0631\u0646 \u0627\u0644\u062e\u0627\u0645\u0633 \u062d\u0648\u0644 \u0627\u0644\u0639\u0645\u0648\u062f \u0627\u0644\u0630\u064a \u0639\u0627\u0634 \u0639\u0644\u064a\u0647 \u0627\u0644\u0642\u062f\u064a\u0633 \u0633\u0645\u0639\u0627\u0646 \u0644\u0645\u062f\u0629 37 \u0639\u0627\u0645\u0627\u064b. \u062a\u0642\u0639 \u0634\u0645\u0627\u0644 \u063a\u0631\u0628 \u062d\u0644\u0628 \u0648\u062a\u0636\u0645 \u0628\u0627\u0632\u064a\u0644\u064a\u0643\u0627 \u0636\u062e\u0645\u0629 \u0648\u0645\u0639\u0645\u0648\u062f\u064a\u0629.","One of the oldest surviving Byzantine churches, built in the 5th century around the pillar where St. Simeon lived for 37 years. Located northwest of Aleppo.",B.G_,36.3342,36.8439,"9:00 \u0635\u0628\u0627\u062d\u0627\u064b - 4:00 \u0645\u0633\u0627\u0621\u064b",null,!0)
