B.ZP=new A.ca("\u0642\u0644\u0639\u0629 \u062f\u0645\u0634\u0642","Citadel of Damascus",null,B.bj,"\u062a\u0642\u0639 \u0641\u064a \u0627\u0644\u0631\u0643\u0646 \u0627\u0644\u0634\u0645\u0627\u0644\u064a \u0627\u0644\u063a\u0631\u0628\u064a \u0645\u0646 \u0623\u0633\u0648\u0627\u0631 \u062f\u0645\u0634\u0642 \u0627\u0644\u0642\u062f\u064a\u0645\u0629. \u0628\u0646\u064a\u062a \u0641\u064a \u0627\u0644\u0642\u0631\u0646 \u0627\u0644\u062d\u0627\u062f\u064a \u0639\u0634\u0631 \u0641\u064a \u0627\u0644\u0639\u0635\u0631 \u0627\u0644\u0633\u0644\u062c\u0648\u0642\u064a\u060c \u0648\u0623\u0639\u064a\u062f \u0628\u0646\u0627\u0624\u0647\u0627 \u0641\u064a \u0627\u0644\u0639\u0635\u0631 \u0627\u0644\u0623\u064a\u0648\u0628\u064a. \u062a\u0636\u0645 12 \u0628\u0631\u062c\u0627\u064b \u0648\u0628\u0648\u0627\u0628\u0629 \u0636\u062e\u0645\u0629. \u0627\u0633\u062a\u062e\u062f\u0645\u062a \u0643\u0633\u062c\u0646 \u0648\u0645\u0642\u0631 \u0639\u0633\u0643\u0631\u064a.","Located in the northwest corner of the old city walls. Built in the 11th century during the Seljuk period and rebuilt under the Ayyubids. Features 12 towers and a monumental gate.",B.a3V,33.5115,36.3012,"9:00 \u0635\u0628\u0627\u062d\u0627\u064b - 4:00 \u0645\u0633\u0627\u0621\u064b",null,!1)
