B.ZS=new A.ca("\u0627\u0644\u062c\u0627\u0645\u0639 \u0627\u0644\u0623\u0645\u0648\u064a \u0627\u0644\u0643\u0628\u064a\u0631","Umayyad Mosque","Great Mosque of Damascus",B.ds,"\u0631\u0627\u0628\u0639 \u0623\u0634\u0647\u0631 \u0645\u0633\u062c\u062f \u0641\u064a \u0627\u0644\u0625\u0633\u0644\u0627\u0645\u060c \u0628\u0646\u0627\u0647 \u0627\u0644\u0648\u0644\u064a\u062f \u0628\u0646 \u0639\u0628\u062f \u0627\u0644\u0645\u0644\u0643 \u0639\u0627\u0645 715\u0645. \u064a\u062a\u0645\u064a\u0632 \u0628\u0645\u0626\u0630\u0646\u062a\u0647 \u0648\u0645\u062d\u0631\u0627\u0628\u0647 \u0627\u0644\u0631\u062e\u0627\u0645\u064a \u0648\u0641\u0646\u0627\u0621\u0647 \u0627\u0644\u0648\u0627\u0633\u0639. \u064a\u0636\u0645 \u0636\u0631\u064a\u062d \u0627\u0644\u0646\u0628\u064a \u064a\u062d\u064a\u0649 \u0639\u0644\u064a\u0647 \u0627\u0644\u0633\u0644\u0627\u0645 \u0648\u064a\u0639\u062a\u0628\u0631 \u062a\u062d\u0641\u0629 \u0645\u0639\u0645\u0627\u0631\u064a\u0629 \u0645\u0646 \u0627\u0644\u0639\u0635\u0631 \u0627\u0644\u0623\u0645\u0648\u064a.","The fourth holiest mosque in Islam, built by Caliph Al-Walid I in 715 AD. Features a magnificent marble mihrab, vast courtyard, and the shrine of John the Baptist.",B.a3T,33.5116,36.3067,"\u0645\u0646 \u0627\u0644\u0641\u062c\u0631 \u062d\u062a\u0649 \u0627\u0644\u0639\u0634\u0627\u0621",null,!1)
