B.ZT=new A.ca("\u0645\u062a\u062d\u0641 \u062a\u062f\u0645\u0631","Palmyra Museum",null,B.e0,"\u064a\u0642\u0639 \u0639\u0646\u062f \u0645\u062f\u062e\u0644 \u0645\u062f\u064a\u0646\u0629 \u062a\u062f\u0645\u0631 \u0627\u0644\u0623\u062b\u0631\u064a\u0629. \u064a\u0636\u0645 \u0645\u062c\u0645\u0648\u0639\u0629 \u063a\u0646\u064a\u0629 \u0645\u0646 \u0627\u0644\u0642\u0637\u0639 \u0627\u0644\u0623\u062b\u0631\u064a\u0629 \u0645\u0646 \u0645\u0645\u0644\u0643\u0629 \u062a\u062f\u0645\u0631: \u062a\u0645\u0627\u062b\u064a\u0644 \u062c\u0646\u0627\u0626\u0632\u064a\u0629\u060c \u0646\u0642\u0648\u0634\u060c \u0641\u0633\u064a\u0641\u0633\u0627\u0621\u060c \u0648\u0623\u0633\u0644\u062d\u0629. \u0623\u063a\u0644\u0628\u0647 \u062f\u0645\u0631 \u0639\u0627\u0645 2015 \u0648\u062c\u0631\u0649 \u062a\u0631\u0645\u064a\u0645\u0647 \u0648\u0625\u0639\u0627\u062f\u0629 \u0627\u0641\u062a\u062a\u0627\u062d\u0647.","Located at the entrance of the Palmyra archaeological site. Houses a rich collection of Palmyrene artifacts: funerary statues, inscriptions, mosaics, and weapons. Largely destroyed in 2015, restored and reopened.",B.a37,34.56,38.267,"9:00 \u0635\u0628\u0627\u062d\u0627\u064b - 4:00 \u0645\u0633\u0627\u0621\u0627\u064b","200 \u0644.\u0633",!1)
B.a6m=s(["https://upload.wikimedia.org/wikipedia/commons/thumb/5/5a/Serjilla.jpg/800px-Serjilla.jpg"],t.s)
B.ZU=new A.ca("\u0627\u0644\u0642\u0631\u0649 \u0627\u0644\u0623\u062b\u0631\u064a\u0629 \u0641\u064a \u0634\u0645\u0627\u0644 \u0633\u0648\u0631\u064a\u0627 - \u0627\u0644\u0645\u062f\u0646 \u0627\u0644\u0645\u0646\u0633\u064a\u0629","Ancient Villages of Northern Syria (Dead Cities)","Ancient Villages of Northern Syria",B.bj,"\u062a\u0636\u0645 \u0623\u0643\u062b\u0631 \u0645\u0646 700 \u0645\u0648\u0642\u0639 \u0623\u062b\u0631\u064a \u0641\u064a \u0634\u0645\u0627\u0644 \u063a\u0631\u0628 \u0633\u0648\u0631\u064a\u0627 \u0628\u064a\u0646 \u062d\u0644\u0628 \u0648\u0625\u062f\u0644\u0628. \u062a\u0639\u0648\u062f \u0644\u0644\u0641\u062a\u0631\u0629 \u0627\u0644\u0631\u0648\u0645\u0627\u0646\u064a\u0629 \u0648\u0627\u0644\u0628\u064a\u0632\u0646\u0637\u064a\u0629 (\u0627\u0644\u0642\u0631\u0646 \u0627\u0644\u0623\u0648\u0644 \u0625\u0644\u0649 \u0627\u0644\u0633\u0627\u0628\u0639 \u0627\u0644\u0645\u064a\u0644\u0627\u062f\u064a) \u0648\u062a\u0636\u0645 \u0643\u0646\u0627\u0626\u0633 \u0648\u0645\u0639\u0627\u0635\u0631 \u0632\u064a\u062a\u0648\u0646 \u0648\u062d\u0645\u0627\u0645\u0627\u062a \u0648\u0641\u064a\u0644\u0627\u062a \u0631\u064a\u0641\u064a\u0629. \u0645\u0646 \u0623\u0647\u0645 \u0627\u0644\u0645\u0648\u0627\u0642\u0639: \u0627\u0644\u0628\u0627\u0631\u0629 \u0648\u0633\u0631\u062c\u064a\u0644\u0627 \u0648\u0642\u0644\u0628 \u0644\u0648\u0632\u0629.","Over 700 abandoned settlements in northwestern Syria dating from the 1st to 7th centuries. Includes remarkably preserved churches, olive presses, baths, and rural villas. Key sites: Al-Bara, Serjilla, Qalb Loze.",B.a6m,35.6833,36.5333,"\u0645\u0641\u062a\u0648\u062d \u0639\u0644\u0649 \u0645\u062f\u0627\u0631 \u0627\u0644\u0633\u0627\u0639\u0629",null,!0)
